import{_ as t,c as r,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"429 Troubleshooting: Rotation des comptes et gestion des erreurs | Antigravity-Manager","description":"Apprenez à résoudre les erreurs 429 avec Antigravity Tools. Maîtrisez l'identification et le traitement des erreurs QUOTA_EXHAUSTED et RATE_LIMIT_EXCEEDED, utilisez Monitor et X-Account-Email pour localiser rapidement les problèmes.","frontmatter":{"title":"429 Troubleshooting: Rotation des comptes et gestion des erreurs | Antigravity-Manager","sidebarTitle":"Erreur 429 : Rotation automatique des comptes","subtitle":"429 Troubleshooting: Rotation des comptes et gestion des erreurs","description":"Apprenez à résoudre les erreurs 429 avec Antigravity Tools. Maîtrisez l'identification et le traitement des erreurs QUOTA_EXHAUSTED et RATE_LIMIT_EXCEEDED, utilisez Monitor et X-Account-Email pour localiser rapidement les problèmes.","tags":["FAQ","Dépannage","Planification des comptes","Erreur 429"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}`),i={name:"fr/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(n,e,l,d,u,c){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="_429-erreur-de-capacite-attentes-correctes-pour-la-rotation-des-comptes-et-meprise-sur-l-epuisement-de-la-capacite-du-modele" tabindex="-1">429/Erreur de capacité : Attentes correctes pour la rotation des comptes et méprise sur l&#39;épuisement de la capacité du modèle <a class="header-anchor" href="#_429-erreur-de-capacite-attentes-correctes-pour-la-rotation-des-comptes-et-meprise-sur-l-epuisement-de-la-capacite-du-modele" aria-label="Permalink to &quot;429/Erreur de capacité : Attentes correctes pour la rotation des comptes et méprise sur l&#39;épuisement de la capacité du modèle&quot;">​</a></h1><h2 id="ce-que-vous-saurez-faire-a-la-fin" tabindex="-1">Ce que vous saurez faire à la fin <a class="header-anchor" href="#ce-que-vous-saurez-faire-a-la-fin" aria-label="Permalink to &quot;Ce que vous saurez faire à la fin&quot;">​</a></h2><ul><li>Distinguer correctement « quota insuffisant » et « limitation en amont » pour éviter les mauvaises interprétations</li><li>Comprendre le mécanisme de rotation automatique et le comportement attendu d&#39;Antigravity Tools</li><li>Savoir localiser rapidement les problèmes et optimiser la configuration lors d&#39;erreurs 429</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><ul><li>Voir une erreur 429 et penser à tort que « le modèle n&#39;a plus de capacité »</li><li>Avoir configuré plusieurs comptes mais continuer à rencontrer fréquemment des erreurs 429, sans savoir s&#39;il s&#39;agit d&#39;un problème de configuration ou de compte</li><li>Ne pas savoir quand le système bascule automatiquement vers un autre compte et quand il « bloque »</li></ul><h2 id="idee-principale" tabindex="-1">Idée principale <a class="header-anchor" href="#idee-principale" aria-label="Permalink to &quot;Idée principale&quot;">​</a></h2><h3 id="qu-est-ce-qu-une-erreur-429" tabindex="-1">Qu&#39;est-ce qu&#39;une erreur 429 ? <a class="header-anchor" href="#qu-est-ce-qu-une-erreur-429" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;une erreur 429 ?&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> est un code d&#39;état HTTP. Dans Antigravity Tools, 429 ne signifie pas seulement « trop de requêtes », mais peut aussi signaler « quota épuisé », « surcharge temporaire du modèle » et d&#39;autres types de « vous ne pouvez pas utiliser pour le moment ».</p><div class="info custom-block"><p class="custom-block-title">Le proxy essaie d&#39;identifier la cause de l&#39;erreur 429</p><p>Le proxy essaie d&#39;analyser <code>error.details[0].reason</code> ou <code>error.message</code> depuis le corps de la réponse, divisant grossièrement les 429 en plusieurs catégories (selon ce qui est réellement renvoyé) :</p><table tabindex="0"><thead><tr><th>Type identifié par le proxy</th><th>Reason / indice courant</th><th>Caractéristique typique</th></tr></thead><tbody><tr><td><strong>Quota épuisé</strong></td><td><code>QUOTA_EXHAUSTED</code> / texte contenant <code>exhausted</code>, <code>quota</code></td><td>Peut nécessiter d&#39;attendre le rafraîchissement du quota</td></tr><tr><td><strong>Limite de taux</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / texte contenant <code>per minute</code>, <code>rate limit</code>, <code>too many requests</code></td><td>Généralement un refroidissement de quelques dizaines de secondes</td></tr><tr><td><strong>Capacité de modèle insuffisante</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / texte contenant <code>model_capacity</code></td><td>Souvent une surcharge temporaire, récupérable plus tard</td></tr><tr><td><strong>Inconnu</strong></td><td>Impossible d&#39;analyser</td><td>Utilise la stratégie de refroidissement par défaut</td></tr></tbody></table></div><h3 id="traitement-automatique-par-antigravity-tools" tabindex="-1">Traitement automatique par Antigravity Tools <a class="header-anchor" href="#traitement-automatique-par-antigravity-tools" aria-label="Permalink to &quot;Traitement automatique par Antigravity Tools&quot;">​</a></h3><p>Lorsqu&#39;une requête rencontre une erreur 429 (et certains états 5xx/surcharge), le proxy fait généralement deux choses côté serveur :</p><ol><li><strong>Enregistrer le temps de refroidissement</strong> : écrire cette erreur dans <code>RateLimitTracker</code>, les sélections de compte ultérieures éviteront activement les comptes « encore en refroidissement ».</li><li><strong>Rotation du compte dans les tentatives</strong> : les Handlers feront plusieurs tentatives au sein d&#39;une seule requête, lors de la nouvelle tentative avec <code>force_rotate=true</code>, déclenchant ainsi TokenManager pour sélectionner le compte disponible suivant.</li></ol><div class="tip custom-block"><p class="custom-block-title">Comment savoir si le compte a été changé ?</p><p>Même si le corps de votre requête ne change pas, la réponse inclut généralement <code>X-Account-Email</code> (ainsi que <code>X-Mapped-Model</code>), vous pouvez l&#39;utiliser pour vérifier « quel compte a réellement été utilisé pour cette requête ».</p></div><h2 id="quand-rencontrerez-vous-des-erreurs-429" tabindex="-1">Quand rencontrerez-vous des erreurs 429 ? <a class="header-anchor" href="#quand-rencontrerez-vous-des-erreurs-429" aria-label="Permalink to &quot;Quand rencontrerez-vous des erreurs 429 ?&quot;">​</a></h2><h3 id="scenario-1-requetes-trop-rapides-sur-un-seul-compte" tabindex="-1">Scénario 1 : Requêtes trop rapides sur un seul compte <a class="header-anchor" href="#scenario-1-requetes-trop-rapides-sur-un-seul-compte" aria-label="Permalink to &quot;Scénario 1 : Requêtes trop rapides sur un seul compte&quot;">​</a></h3><p><strong>Phénomène</strong> : même avec un seul compte, l&#39;envoi d&#39;un grand nombre de requêtes dans un court laps de temps déclenche 429.</p><p><strong>Cause</strong> : chaque compte a ses propres limites de taux (RPM/TPM), dépasser entraîne une limitation.</p><p><strong>Solution</strong> :</p><ul><li>Augmenter le nombre de comptes</li><li>Réduire la fréquence des requêtes</li><li>Utiliser le mode de compte fixe pour disperser la pression (voir « Mode de compte fixe »)</li></ul><h3 id="scenario-2-tous-les-comptes-limites-simultanement" tabindex="-1">Scénario 2 : Tous les comptes limités simultanément <a class="header-anchor" href="#scenario-2-tous-les-comptes-limites-simultanement" aria-label="Permalink to &quot;Scénario 2 : Tous les comptes limités simultanément&quot;">​</a></h3><p><strong>Phénomène</strong> : plusieurs comptes, mais tous renvoient 429.</p><p><strong>Cause</strong> :</p><ul><li>Le nombre total de comptes est insuffisant pour supporter votre fréquence de requêtes</li><li>Tous les comptes déclenchent la limitation/surcharge presque simultanément</li></ul><p><strong>Solution</strong> :</p><ul><li>Ajouter plus de comptes</li><li>Ajuster le mode de planification en « Performance优先 » (sauter la session sticky et la réutilisation de fenêtre 60s)</li><li>Vérifier si la protection du quota exclut par erreur des comptes disponibles</li></ul><h3 id="scenario-3-compte-mal-identifie-par-la-protection-du-quota" tabindex="-1">Scénario 3 : Compte mal identifié par la protection du quota <a class="header-anchor" href="#scenario-3-compte-mal-identifie-par-la-protection-du-quota" aria-label="Permalink to &quot;Scénario 3 : Compte mal identifié par la protection du quota&quot;">​</a></h3><p><strong>Phénomène</strong> : le quota d&#39;un compte est très suffisant, mais le système continue de le sauter.</p><p><strong>Cause</strong> :</p><ul><li>La <strong>protection du quota</strong> est activée, le seuil est trop élevé</li><li>Le quota de modèle spécifique de ce compte est inférieur au seuil</li><li>Le compte est manuellement marqué comme <code>proxy_disabled</code></li></ul><p><strong>Solution</strong> :</p><ul><li>Vérifier les paramètres de protection du quota (Settings → Quota Protection), ajuster le seuil et les modèles surveillés selon votre intensité d&#39;utilisation</li><li>Dans les données du compte, vérifier <code>protected_models</code>, confirmer si il est sauté par la stratégie de protection</li></ul><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-identifier-le-type-d-erreur-429" tabindex="-1">Étape 1 : Identifier le type d&#39;erreur 429 <a class="header-anchor" href="#etape-1-identifier-le-type-d-erreur-429" aria-label="Permalink to &quot;Étape 1 : Identifier le type d&#39;erreur 429&quot;">​</a></h3><p><strong>Pourquoi</strong> : différents types d&#39;erreurs 429 nécessitent des méthodes de traitement différentes.</p><p>Dans Proxy Monitor, examinez le corps de réponse des erreurs 429, concentrez-vous sur deux types d&#39;informations :</p><ul><li><strong>Raison</strong> : <code>error.details[0].reason</code> (par exemple <code>RATE_LIMIT_EXCEEDED</code>, <code>QUOTA_EXHAUSTED</code>) ou <code>error.message</code></li><li><strong>Temps d&#39;attente</strong> : <code>RetryInfo.retryDelay</code> ou <code>details[0].metadata.quotaResetDelay</code> (si présent)</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Si le temps d&#39;attente peut être trouvé dans le corps de la réponse (par exemple <code>RetryInfo.retryDelay</code> ou <code>quotaResetDelay</code>), le proxy attendra généralement un court moment avant de réessayer.</li><li>S&#39;il n&#39;y a pas de temps d&#39;attente, le proxy appliquera une période de « refroidissement » selon la stratégie intégrée, et passera directement au compte suivant lors de la nouvelle tentative.</li></ul><h3 id="etape-2-verifier-la-configuration-de-la-planification-des-comptes" tabindex="-1">Étape 2 : Vérifier la configuration de la planification des comptes <a class="header-anchor" href="#etape-2-verifier-la-configuration-de-la-planification-des-comptes" aria-label="Permalink to &quot;Étape 2 : Vérifier la configuration de la planification des comptes&quot;">​</a></h3><p><strong>Pourquoi</strong> : la configuration de la planification affecte directement la fréquence et la priorité de la rotation des comptes.</p><p>Accédez à la page <strong>API Proxy</strong>, consultez la stratégie de planification :</p><table tabindex="0"><thead><tr><th>Élément de configuration</th><th>Description</th><th>Valeur par défaut/suggestion</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>Mode de planification</td><td><code>Balance</code> (par défaut)</td></tr><tr><td><strong>Preferred Account</strong></td><td>Mode de compte fixe</td><td>Non sélectionné (par défaut)</td></tr></tbody></table><p><strong>Comparaison des modes de planification</strong> :</p><table tabindex="0"><thead><tr><th>Mode</th><th>Stratégie de réutilisation de compte</th><th>Traitement de la limitation</th><th>Scénario applicable</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>Active session sticky et réutilisation de fenêtre 60s</td><td><strong>Attend en priorité</strong>, améliore considérablement le taux de succès du Prompt Caching</td><td>Conversation/taux de succès du cache élevé</td></tr><tr><td><strong>Balance</strong></td><td>Active session sticky et réutilisation de fenêtre 60s</td><td><strong>Bascule immédiatement</strong> vers le compte de secours, équilibre taux de succès et performance</td><td>Scénario général, par défaut</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>Saute session sticky et réutilisation de fenêtre 60s, mode round-robin pur</td><td>Bascule immédiatement, répartition de charge la plus équilibrée</td><td>Haute concurrence, requêtes sans état</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Cache prioritaire vs mode équilibré</p><p>Si vous utilisez Prompt Caching et souhaitez améliorer le taux de succès du cache, choisissez <code>CacheFirst</code> — en cas de limitation, il attendra plutôt que de basculer immédiatement. Si vous privilégiez le taux de succès des requêtes plutôt que le cache, choisissez <code>Balance</code> — en cas de limitation, il basculera immédiatement.</p></div><div class="tip custom-block"><p class="custom-block-title">Mode Performance优先</p><p>Si vos requêtes sont sans état (comme la génération d&#39;images, requêtes indépendantes), essayez <code>PerformanceFirst</code>. Il sautera la session sticky et la réutilisation de fenêtre 60s, facilitant la répartition sur différents comptes pour les requêtes consécutives.</p></div><h3 id="etape-3-verifier-si-la-rotation-des-comptes-fonctionne-normalement" tabindex="-1">Étape 3 : Vérifier si la rotation des comptes fonctionne normalement <a class="header-anchor" href="#etape-3-verifier-si-la-rotation-des-comptes-fonctionne-normalement" aria-label="Permalink to &quot;Étape 3 : Vérifier si la rotation des comptes fonctionne normalement&quot;">​</a></h3><p><strong>Pourquoi</strong> : confirmer que le système peut basculer automatiquement vers d&#39;autres comptes.</p><p><strong>Méthode 1 : Regarder les en-têtes de réponse</strong></p><p>Utilisez curl ou votre propre client pour imprimer les en-têtes de réponse, observez si <code>X-Account-Email</code> change.</p><p><strong>Méthode 2 : Vérifier les journaux</strong></p><p>Ouvrez le fichier de journal (selon l&#39;emplacement de votre système), recherchez <code>🔄 [Token Rotation]</code> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>Méthode 3 : Utiliser Proxy Monitor</strong></p><p>Dans la page <strong>Monitor</strong>, consultez les journaux de requêtes, concentrez-vous sur :</p><ul><li>Le champ <strong>Account</strong> bascule-t-il entre différents comptes</li><li>Après les requêtes avec <strong>Status</strong> 429, y a-t-il des requêtes réussies utilisant des comptes différents</li></ul><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Lorsqu&#39;un compte renvoie 429, les requêtes suivantes basculent automatiquement vers d&#39;autres comptes</li><li>Si vous voyez plusieurs requêtes utilisant le même compte et échouant toutes, cela peut être un problème de configuration de planification</li></ul><h3 id="etape-4-optimiser-la-priorite-des-comptes" tabindex="-1">Étape 4 : Optimiser la priorité des comptes <a class="header-anchor" href="#etape-4-optimiser-la-priorite-des-comptes" aria-label="Permalink to &quot;Étape 4 : Optimiser la priorité des comptes&quot;">​</a></h3><p><strong>Pourquoi</strong> : faire utiliser au système les comptes avec quota élevé/niveau élevé en priorité, réduisant la probabilité de 429.</p><p>Dans TokenManager, le système effectuera un tri du pool de comptes avant de sélectionner un compte (imprimera <code>🔄 [Token Rotation] Accounts: ...</code>) :</p><ol><li><strong>Priorité du niveau d&#39;abonnement</strong> : ULTRA &gt; PRO &gt; FREE</li><li><strong>Priorité du pourcentage de quota</strong> : même niveau, quota élevé en premier</li><li><strong>Point d&#39;entrée du tri</strong> : ce tri se produit côté proxy, le compte finalement utilisé dépend du tri côté proxy + jugement de disponibilité.</li></ol><div class="info custom-block"><p class="custom-block-title">Principe du tri intelligent (côté proxy)</p><p>La priorité est <code>ULTRA &gt; PRO &gt; FREE</code> ; même niveau d&#39;abonnement, tri par <code>remaining_quota</code> (pourcentage de quota restant maximum du compte) décroissant.</p></div><p><strong>Action</strong> :</p><ul><li>Faites glisser les comptes pour ajuster l&#39;ordre d&#39;affichage (optionnel)</li><li>Rafraîchir les quotas (Accounts → Rafraîchir tous les quotas)</li><li>Vérifier le niveau d&#39;abonnement et le quota des comptes</li></ul><h2 id="attention-aux-pieges" tabindex="-1">Attention aux pièges <a class="header-anchor" href="#attention-aux-pieges" aria-label="Permalink to &quot;Attention aux pièges&quot;">​</a></h2><h3 id="❌-erreur-1-confondre-429-avec-«-le-modele-n-a-plus-de-capacite-»" tabindex="-1">❌ Erreur 1 : Confondre 429 avec « le modèle n&#39;a plus de capacité » <a class="header-anchor" href="#❌-erreur-1-confondre-429-avec-«-le-modele-n-a-plus-de-capacite-»" aria-label="Permalink to &quot;❌ Erreur 1 : Confondre 429 avec « le modèle n&#39;a plus de capacité »&quot;">​</a></h3><p><strong>Phénomène</strong> : voir une erreur 429 et penser que le modèle n&#39;a plus de capacité.</p><p><strong>Compréhension correcte</strong> :</p><ul><li>429 est une <strong>limitation</strong>, pas un problème de capacité</li><li>Augmenter le nombre de comptes peut réduire la probabilité de 429</li><li>Ajuster le mode de planification peut améliorer la vitesse de basculement</li></ul><h3 id="❌-erreur-2-seuil-de-protection-du-quota-trop-eleve" tabindex="-1">❌ Erreur 2 : Seuil de protection du quota trop élevé <a class="header-anchor" href="#❌-erreur-2-seuil-de-protection-du-quota-trop-eleve" aria-label="Permalink to &quot;❌ Erreur 2 : Seuil de protection du quota trop élevé&quot;">​</a></h3><p><strong>Phénomène</strong> : quota suffisant mais le système continue de sauter les comptes.</p><p><strong>Cause</strong> : Quota Protection ajoute les modèles sous le seuil dans <code>protected_models</code> du compte, le proxy sautera « les modèles protégés » lors de la planification. Si le seuil est trop élevé, cela peut entraîner une exclusion excessive de comptes disponibles.</p><p><strong>Correction</strong> :</p><ul><li>Retournez à <strong>Settings → Quota Protection</strong>, ajustez les modèles surveillés et le seuil</li><li>Si vous voulez savoir quels modèles sont protégés, regardez <code>protected_models</code> dans les données du compte</li></ul><h3 id="❌-erreur-3-mode-de-compte-fixe-empechant-la-rotation" tabindex="-1">❌ Erreur 3 : Mode de compte fixe empêchant la rotation <a class="header-anchor" href="#❌-erreur-3-mode-de-compte-fixe-empechant-la-rotation" aria-label="Permalink to &quot;❌ Erreur 3 : Mode de compte fixe empêchant la rotation&quot;">​</a></h3><p><strong>Phénomène</strong> : configuration de <code>Preferred Account</code>, mais le système « bloque » après la limitation de ce compte.</p><p><strong>Cause</strong> : en mode de compte fixe, le système utilise prioritairement le compte spécifié, ne bascule vers round-robin que lorsque le compte n&#39;est pas disponible.</p><p><strong>Correction</strong> :</p><ul><li>Si vous n&#39;avez pas besoin de compte fixe, videz <code>Preferred Account</code></li><li>Ou assurez-vous que le quota du compte fixe est suffisant pour éviter la limitation</li></ul><h2 id="points-de-controle-✅" tabindex="-1">Points de contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de contrôle ✅&quot;">​</a></h2><ul><li>[ ] Pouvez distinguer quota insuffisant et limitation en amont</li><li>[ ] Savez comment consulter les détails des erreurs 429 dans Proxy Monitor</li><li>[ ] Comprenez la différence entre les trois modes de planification et leurs scénarios d&#39;utilisation</li><li>[ ] Savez comment vérifier si la rotation des comptes fonctionne normalement</li><li>[ ] Pouvez optimiser la priorité des comptes et vérifier la stratégie de protection du quota</li></ul><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><h3 id="q1-pourquoi-j-ai-plusieurs-comptes-mais-rencontre-toujours-des-429" tabindex="-1">Q1 : Pourquoi j&#39;ai plusieurs comptes mais rencontre toujours des 429 ? <a class="header-anchor" href="#q1-pourquoi-j-ai-plusieurs-comptes-mais-rencontre-toujours-des-429" aria-label="Permalink to &quot;Q1 : Pourquoi j&#39;ai plusieurs comptes mais rencontre toujours des 429 ?&quot;">​</a></h3><p>A : Causes possibles :</p><ol><li>Tous les comptes déclenchent la limitation simultanément (fréquence de requêtes trop élevée)</li><li>Les requêtes consécutives réutilisent le même compte sous « réutilisation de fenêtre 60s », facilitant l&#39;atteinte de la limitation sur un seul compte</li><li>La protection du quota exclut par erreur les comptes disponibles</li><li>Le nombre total de comptes est insuffisant pour supporter votre fréquence de requêtes</li></ol><p><strong>Solution</strong> :</p><ul><li>Ajouter plus de comptes</li><li>Utiliser le mode <code>PerformanceFirst</code></li><li>Vérifier si Quota Protection a ajouté le modèle que vous utilisez dans <code>protected_models</code> (si nécessaire, ajustez les modèles surveillés et le seuil)</li><li>Réduire la fréquence des requêtes</li></ul><h3 id="q2-les-erreurs-429-sont-elles-reessayees-automatiquement" tabindex="-1">Q2 : Les erreurs 429 sont-elles réessayées automatiquement ? <a class="header-anchor" href="#q2-les-erreurs-429-sont-elles-reessayees-automatiquement" aria-label="Permalink to &quot;Q2 : Les erreurs 429 sont-elles réessayées automatiquement ?&quot;">​</a></h3><p>A : Elles sont réessayées automatiquement au sein d&#39;une seule requête. <strong>La limite de tentatives est généralement 3 fois</strong>, le calcul spécifique est <code>min(3, taille du pool de comptes)</code>, et au moins 1 tentative.</p><p><strong>Exemple de nombre de tentatives</strong> :</p><ul><li>Pool de 1 compte → 1 tentative (pas de nouvelle tentative)</li><li>Pool de 2 comptes → 2 tentatives (1 nouvelle tentative)</li><li>Pool de 3 ou plus de comptes → 3 tentatives (2 nouvelles tentatives)</li></ul><p><strong>Processus approximatif</strong> :</p><ol><li>Enregistrer les informations de limitation/surcharge (entrer dans <code>RateLimitTracker</code>)</li><li>Si le temps d&#39;attente peut être analysé (par exemple <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>), attendez un court moment avant de continuer</li><li>Lors de la nouvelle tentative, forcer la rotation du compte (<code>force_rotate=true</code> quand <code>attempt &gt; 0</code>), essayer d&#39;initier la requête en amont avec le compte disponible suivant</li></ol><p>Si toutes les tentatives échouent, le proxy renverra l&#39;erreur au client ; en même temps, vous pouvez toujours voir les comptes réellement utilisés à partir des en-têtes de réponse (comme <code>X-Account-Email</code>) ou Proxy Monitor.</p><h3 id="q3-comment-verifier-pendant-combien-de-temps-un-compte-a-ete-limite" tabindex="-1">Q3 : Comment vérifier pendant combien de temps un compte a été limité ? <a class="header-anchor" href="#q3-comment-verifier-pendant-combien-de-temps-un-compte-a-ete-limite" aria-label="Permalink to &quot;Q3 : Comment vérifier pendant combien de temps un compte a été limité ?&quot;">​</a></h3><p>A : Deux façons :</p><p><strong>Méthode 1</strong> : Vérifier les journaux, rechercher <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>Méthode 2</strong> : Le journal affichera le temps d&#39;attente restant</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-protection-du-quota-et-limitation-sont-elles-la-meme-chose" tabindex="-1">Q4 : Protection du quota et limitation sont-elles la même chose ? <a class="header-anchor" href="#q4-protection-du-quota-et-limitation-sont-elles-la-meme-chose" aria-label="Permalink to &quot;Q4 : Protection du quota et limitation sont-elles la même chose ?&quot;">​</a></h3><p>A : Non.</p><table tabindex="0"><thead><tr><th>Caractéristique</th><th>Protection du quota</th><th>Suivi de la limitation</th></tr></thead><tbody><tr><td><strong>Condition de déclenchement</strong></td><td>Quota de modèle sous le seuil</td><td>Réception d&#39;une erreur 429</td></tr><tr><td><strong>Portée</strong></td><td>Modèle spécifique</td><td>Compte entier</td></tr><tr><td><strong>Durée</strong></td><td>Jusqu&#39;à récupération du quota</td><td>Décidé par l&#39;amont (généralement quelques secondes à quelques minutes)</td></tr><tr><td><strong>Comportement</strong></td><td>Sauter ce modèle</td><td>Sauter ce compte</td></tr></tbody></table><h3 id="q5-comment-forcer-le-basculement-immediat-du-compte" tabindex="-1">Q5 : Comment forcer le basculement immédiat du compte ? <a class="header-anchor" href="#q5-comment-forcer-le-basculement-immediat-du-compte" aria-label="Permalink to &quot;Q5 : Comment forcer le basculement immédiat du compte ?&quot;">​</a></h3><p>A : Commencez par « faciliter le changement de compte pour la prochaine requête » :</p><ol><li><strong>Niveau de planification</strong> : passez en <code>PerformanceFirst</code>, sautez session sticky et réutilisation de fenêtre 60s</li><li><strong>Compte fixe</strong> : si <code>Preferred Account</code> est activé, videz-le d&#39;abord, sinon il utilisera prioritairement le compte fixe (jusqu&#39;à limitation/protection)</li><li><strong>Pool de comptes</strong> : augmentez le nombre de comptes, facilitant la recherche de compte de remplacement lors de la limitation d&#39;un compte</li></ol><p>Dans une seule requête, le proxy forcera également la rotation lors de la nouvelle tentative (<code>attempt &gt; 0</code> déclenchera <code>force_rotate=true</code>), mais le nombre de tentatives est soumis à la limite.</p><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><ul><li>429 dans Antigravity Tools est un signal « temporairement indisponible en amont », pouvant être causé par la limitation de taux, l&#39;épuisement du quota, l&#39;insuffisance de capacité du modèle, etc.</li><li>Le proxy enregistre le temps de refroidissement et essaie de faire pivoter les comptes lors des nouvelles tentatives au sein d&#39;une seule requête (mais le nombre de tentatives est limité)</li><li>Le mode de planification, Quota Protection et le nombre de comptes affectent tous la probabilité et la vitesse de récupération des erreurs 429</li><li>Proxy Monitor, les en-têtes de réponse <code>X-Account-Email</code> et les journaux peuvent localiser rapidement les problèmes</li></ul><h2 id="prochaine-lecon" tabindex="-1">Prochaine leçon <a class="header-anchor" href="#prochaine-lecon" aria-label="Permalink to &quot;Prochaine leçon&quot;">​</a></h2><blockquote><p>La prochaine leçon, nous apprendrons <strong><a href="./../404-base-url/">404/Incompatibilité de chemin : Base URL, préfixe /v1 et clients « double chemin »</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment l&#39;erreur d&#39;intégration la plus courante (404) se produit</li><li>Différences de concaténation base_url entre différents clients</li><li>Comment corriger rapidement les problèmes 404</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Heure de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Analyse du délai de nouvelle tentative 429 (RetryInfo / quotaResetDelay)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Outil d&#39;analyse Duration</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>Énumération du mode de planification (CacheFirst/Balance/PerformanceFirst)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>Analyse de la raison de limitation et stratégie de refroidissement par défaut</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>Définition de constante MAX_RETRY_ATTEMPTS (handler OpenAI)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>Calcul du nombre de tentatives (max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size))</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>Handler OpenAI : marquer limitation et réessayer/pivot lors de 429/5xx</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>Priorité de tri des comptes (ULTRA &gt; PRO &gt; FREE + remaining_quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>Réutilisation de fenêtre 60s + éviter limitation/protection du quota</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>Point d&#39;entrée d&#39;enregistrement de limitation (mark_rate_limited)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>Verrouillage précis 429 / rafraîchissement de quota en temps réel / stratégie de dégradation (mark_rate_limited_async)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code> : nombre maximum de nouvelles tentatives au sein d&#39;une seule requête (handler OpenAI/Gemini)</li><li><code>60</code> : réutilisation de fenêtre 60 secondes (activée uniquement dans les modes autres que <code>PerformanceFirst</code>)</li><li><code>5</code> : délai d&#39;expiration de récupération de token (secondes)</li><li><code>300</code> : seuil de rafraîchissement anticipé de token (secondes, 5 minutes)</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>parse_retry_delay()</code> : extraire le délai de nouvelle tentative de la réponse d&#39;erreur 429</li><li><code>get_token_internal()</code> : logique principale de sélection et rotation de compte</li><li><code>mark_rate_limited()</code> : marquer le compte comme état de limitation</li></ul></details>`,116)])])}const h=t(i,[["render",s]]);export{m as __pageData,h as default};
